import asyncio
from dataclasses import dataclass, field
from typing import List, Dict

@dataclass
class Player:
    id: int
    x: float
    y: float
    z: float

@dataclass
class GameState:
    players: List[Player] = field(default_factory=list)

class GameServer:
    def __init__(self):
        self.clients = set()
        self.game_state = GameState()

    async def handle_client(self, reader, writer):
        addr = writer.get_extra_info('peername')
        print(f"New client connected: {addr}")
        self.clients.add(writer)
        
        while True:
            data = await reader.read(1024)
            if not data:
                break
            message = data.decode()
            if message == "REQUEST_STATE":
                await self.send_state(writer)
        
        self.clients.remove(writer)
        writer.close()
        await writer.wait_closed()

    async def send_state(self, client):
        state_data = {
            'players': [
                {'id': player.id, 'x': player.x, 'y': player.y, 'z': player.z}
                for player in self.game_state.players
            ]
        }
        client.write(state_data.encode())
        await client.drain()

    async def update_game_state(self):
        while True:
            # Simulate updating game state (e.g., moving players)
            for i, player in enumerate(self.game_state.players):
                player.x += 1 * (i % 2) - 0.5
                player.y += 1 * ((i + 1) % 2) - 0.5
            await asyncio.sleep(0.5)

    async def start_server(self, host: str = '127.0.0.1', port: int = 8888):
        server = await asyncio.start_server(self.handle_client, host, port)
        addr = server.sockets[0].getsockname()
        print(f'Serving on {addr}')

        async with server:
            await server.serve_forever()

    def add_player(self, player: Player):
        self.game_state.players.append(player)

# Example usage
if __name__ == "__main__":
    server = GameServer()
    asyncio.create_task(server.update_game_state())
    server.add_player(Player(id=1, x=0, y=0, z=0))
    server.add_player(Player(id=2, x=5, y=5, z=5))
    asyncio.run(server.start_server())